# Force Field Background

Interactive particle system powered by p5.js that renders a dense force-field of orbiting dots. Particles react to cursor position, creating a magnetic repulsion effect across the full viewport.

## Use when
- Creating a dark landing page hero that needs strong interactive depth.
- Showcasing a product or feature with an immersive, tech-forward ambient background.
- Adding an interactive demo area where cursor engagement enhances engagement.

## Stack
- Framework: react
- Libraries: p5, three, lucide-react

## Install
```bash
npm install p5 three lucide-react
```

## Component — force-field-background.tsx
```tsx
import React, { useEffect, useRef } from 'react';
import p5 from 'p5';

export interface ForceFieldBackgroundProps {
  particleCount?: number;
  repulsionRadius?: number;
  repulsionStrength?: number;
  color?: string;
  backgroundColor?: string;
  className?: string;
}

export const ForceFieldBackground: React.FC<ForceFieldBackgroundProps> = ({
  particleCount = 200,
  repulsionRadius = 100,
  repulsionStrength = 5,
  color = '#5227FF',
  backgroundColor = '#0a0a0a',
  className = ''
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const p5InstanceRef = useRef<p5 | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const sketch = (p: p5) => {
      let particles: Array<{
        x: number; y: number; vx: number; vy: number;
        ox: number; oy: number; size: number;
      }> = [];

      p.setup = () => {
        const canvas = p.createCanvas(
          containerRef.current!.clientWidth,
          containerRef.current!.clientHeight
        );
        canvas.parent(containerRef.current!);

        for (let i = 0; i < particleCount; i++) {
          particles.push({
            x: p.random(p.width),
            y: p.random(p.height),
            vx: 0, vy: 0,
            ox: 0, oy: 0,
            size: p.random(2, 5)
          });
        }
      };

      p.draw = () => {
        p.background(backgroundColor);

        particles.forEach(particle => {
          const dx = p.mouseX - particle.x;
          const dy = p.mouseY - particle.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < repulsionRadius && dist > 0) {
            const force = (repulsionRadius - dist) / repulsionRadius;
            particle.vx -= (dx / dist) * force * repulsionStrength;
            particle.vy -= (dy / dist) * force * repulsionStrength;
          }

          particle.vx *= 0.9;
          particle.vy *= 0.9;
          particle.x += particle.vx;
          particle.y += particle.vy;

          particle.x = (particle.x + p.width) % p.width;
          particle.y = (particle.y + p.height) % p.height;

          p.fill(color);
          p.noStroke();
          p.circle(particle.x, particle.y, particle.size);
        });
      };

      p.windowResized = () => {
        if (containerRef.current) {
          p.resizeCanvas(
            containerRef.current.clientWidth,
            containerRef.current.clientHeight
          );
        }
      };
    };

    p5InstanceRef.current = new p5(sketch);

    return () => {
      p5InstanceRef.current?.remove();
    };
  }, [particleCount, repulsionRadius, repulsionStrength, color, backgroundColor]);

  return <div ref={containerRef} className={`w-full h-full ${className}`} />;
};

export default ForceFieldBackground;
```

## Demo
```tsx
import React from 'react';
import ForceFieldBackground from './Component';

export default function App() {
  return (
    <div className="w-full h-screen relative overflow-hidden bg-[#0a0a0a]">
      <ForceFieldBackground
        particleCount={200}
        color="#5227FF"
        repulsionRadius={120}
      />
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <h1 className="text-white text-4xl font-bold">Force Field</h1>
      </div>
    </div>
  );
}
```

## Notes
- Requires p5.js which adds ~800 KB to the bundle. Consider lazy-loading.
- The raw file also includes GooeyGradientBackground, TubesBackground, ParallaxStarsBackground, and PastelGradientBackground as alternative reference implementations in the same source.
